const results = [];
for (const item of $input.all()) {
  const e = item.json;
  if (!e || e.noEvents) continue;
  const eid = String(e.iCalUId || e.id || '');
  // Combine bodyPreview + body.content for richer text matching
  const bodyPreview = String(e.bodyPreview || '');
  const bodyContent = (e.body && e.body.content) ? String(e.body.content) : '';
  const combinedBody = bodyPreview + (bodyContent ? '\n' + bodyContent : '');
  results.push({ json: {
    calendarSource: 'Primary',
    calendarOwnerEmail: 'user@example.com',
    outlookEventId: eid,
    subject: String(e.subject || ''),
    startDateTime: e.start ? String(e.start.dateTime || '') : '',
    startTimezone: e.start ? String(e.start.timeZone || '') : '',
    endDateTime: e.end ? String(e.end.dateTime || '') : '',
    organizerEmail: e.organizer && e.organizer.emailAddress ? String(e.organizer.emailAddress.address || '') : '',
    organizerName: e.organizer && e.organizer.emailAddress ? String(e.organizer.emailAddress.name || '') : '',
    attendeesRaw: Array.isArray(e.attendees) ? e.attendees : [],
    isCancelled: e.isCancelled === true,
    isAllDay: e.isAllDay === true,
    lastModified: String(e.lastModifiedDateTime || ''),
    bodyPreview: combinedBody
  }});
}
return results.length > 0 ? results : [{ json: { noEvents: true } }];

