const internalDomains = ['example.com'];
const testMode = $('Meeting Detection Config').item.json.testMode === true;
const testAllowedEventId = String($('Meeting Detection Config').item.json.testAllowedEventId || '');

function isInternal(email) {
  if (!email) return true;
  const domain = (email.split('@')[1] || '').toLowerCase();
  return internalDomains.some(d => domain === d.toLowerCase());
}

function isValidEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

// Parse invitee email from Calendly-style body text.
// Checks multiple patterns and handles \r\n line endings.
function parseCalendlyEmail(text) {
  if (!text) return null;
  // Strip HTML tags if present
  const plain = text.replace(/<[^>]+>/g, ' ').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&');
  const patterns = [
    /Invitee\s+Email\s*:\s*([^\s\r\n,<>"]+)/i,
    /Guest\s+Email\s*:\s*([^\s\r\n,<>"]+)/i,
    /mailto:([^\s\r\n,<>"?]+@[^\s\r\n,<>"?]+)/i
  ];
  for (const pattern of patterns) {
    const match = plain.match(pattern);
    if (match && match[1]) {
      const email = match[1].trim().toLowerCase().replace(/[.,;]+$/, '');
      if (isValidEmail(email)) return email;
    }
  }
  return null;
}

function parseCalendlyName(text) {
  if (!text) return null;
  const plain = text.replace(/<[^>]+>/g, ' ');
  const match = plain.match(/Invitee\s*:\s*([^\r\n<]+)/i);
  return match ? match[1].trim() : null;
}

const results = [];
for (const item of $input.all()) {
  const e = item.json;
  if (e.noEvents) continue;
  if (e.isCancelled === true) continue;
  if (!e.outlookEventId || !e.startDateTime) continue;
  if (testMode && e.outlookEventId !== testAllowedEventId) continue;

  const internal = [];
  const external = [];

  // SOURCE A: Attendees array
  for (const att of (e.attendeesRaw || [])) {
    const email = att.emailAddress ? String(att.emailAddress.address || '') : '';
    const name  = att.emailAddress ? String(att.emailAddress.name  || '') : '';
    if (!email) continue;
    if (isInternal(email)) { internal.push(email); }
    else if (!external.find(a => a.email === email.toLowerCase())) {
      external.push({ email: email.toLowerCase().trim(), name });
    }
  }

  // SOURCE B: Organizer (if external)
  if (e.organizerEmail && !isInternal(e.organizerEmail)) {
    if (!external.find(a => a.email === e.organizerEmail.toLowerCase())) {
      external.push({ email: e.organizerEmail.toLowerCase().trim(), name: e.organizerName });
    }
  }

  // SOURCE C: Calendly body parser
  // Always run — use as primary if no external from A/B,
  // OR if the only externals found look like system addresses (no Lead match likely)
  let calendlyParsed = false;
  const bodyText = String(e.bodyPreview || '');

  if (external.length === 0) {
    // No external attendees from A/B — try body parser
    const parsedEmail = parseCalendlyEmail(bodyText);
    if (parsedEmail && !isInternal(parsedEmail)) {
      const parsedName = parseCalendlyName(bodyText) || parsedEmail;
      external.push({ email: parsedEmail, name: parsedName });
      calendlyParsed = true;
    }
  }

  if (external.length === 0) continue;

  results.push({ json: {
    calendarSource: String(e.calendarSource || ''),
    calendarOwnerEmail: String(e.calendarOwnerEmail || ''),
    outlookEventId: String(e.outlookEventId || ''),
    subject: String(e.subject || ''),
    startDateTime: String(e.startDateTime || ''),
    startTimezone: String(e.startTimezone || ''),
    endDateTime: String(e.endDateTime || ''),
    organizerEmail: String(e.organizerEmail || ''),
    organizerName: String(e.organizerName || ''),
    bodyPreview: bodyText,
    internalAttendees: internal.join(', '),
    externalAttendees: external,
    externalAttendeeEmails: external.map(a => a.email).join(', '),
    calendlyParsed
  }});
}
return results.length > 0 ? results : [{ json: { noEventsToProcess: true } }];

const seen = new Set();
const results = [];
for (const item of $input.all()) {
  const e = item.json;
  if (e.noEvents || e.noEventsToProcess || e.noMatchJobs) continue;
  if (!e.outlookEventId || !e.externalAttendees || e.externalAttendees.length === 0) continue;
  for (const att of e.externalAttendees) {
    const dedupeKey = e.outlookEventId + '_' + att.email;
    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);
    results.push({ json: {
      calendarSource: String(e.calendarSource || ''),
      calendarOwnerEmail: String(e.calendarOwnerEmail || ''),
      outlookEventId: String(e.outlookEventId || ''),
      subject: String(e.subject || ''),
      startDateTime: String(e.startDateTime || ''),
      startTimezone: String(e.startTimezone || ''),
      endDateTime: String(e.endDateTime || ''),
      organizerEmail: String(e.organizerEmail || ''),
      organizerName: String(e.organizerName || ''),
      bodyPreview: String(e.bodyPreview || ''),
      internalAttendees: String(e.internalAttendees || ''),
      externalAttendeeEmails: String(e.externalAttendeeEmails || ''),
      currentAttendeeEmail: String(att.email || ''),
      currentAttendeeName: String(att.name || att.email || ''),
      calendlyParsed: e.calendlyParsed === true
    }});
  }
}
if (results.length === 0) return [{ json: { noMatchJobs: true } }];
return results;

// EXACT EMAIL MATCH GUARD + FINAL DEDUPE
// Dictionary: email -> [eventCtx, ...] (one per unique outlookEventId)
// Hard rule: only one output per unique leadId + outlookEventId + extractedEmail

const expandItems = $('Expand \u2014 One Item Per External Attendee').all();

// Build email -> array of expand contexts (one per unique event)
const expandByEmail = {};
for (const ei of expandItems) {
  const email = String(ei.json.currentAttendeeEmail || '').toLowerCase().trim();
  if (email) {
    if (!expandByEmail[email]) expandByEmail[email] = [];
    expandByEmail[email].push(ei.json);
  }
}

const seen = new Set(); // dedupe: leadId|outlookEventId|extractedEmail
const results = [];

for (const inputItem of $input.all()) {
  const item = inputItem.json;
  const sfEmail = String(item.Email || '').toLowerCase().trim();
  const sfId    = String(item.Id || '');
  if (!sfId || sfId.length < 5 || !sfEmail) continue;

  const ctxList = expandByEmail[sfEmail];
  if (!ctxList || ctxList.length === 0) continue;

  for (const eventCtx of ctxList) {
    const extractedEmail = String(eventCtx.currentAttendeeEmail || '').toLowerCase().trim();
    if (extractedEmail !== sfEmail) continue; // hard exact-match guard

    // Final dedupe: one output per unique lead+event+email combination
    const dedupeKey = sfId + '|' + String(eventCtx.outlookEventId || '') + '|' + extractedEmail;
    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);

    results.push({ json: {
      leadFound: true,
      leadId: sfId,
      leadName: String(item.Name || ''),
      leadStatus: String(item.Status || ''),
      leadEmail: String(item.Email || ''),
      leadOwnerId: String(item.OwnerId || ''),
      totalMeetingsBooked: Number(item.Total_Meetings_Booked__c || 0),
      calendarSource: String(eventCtx.calendarSource || ''),
      outlookEventId: String(eventCtx.outlookEventId || ''),
      subject: String(eventCtx.subject || ''),
      startDateTime: String(eventCtx.startDateTime || ''),
      startTimezone: String(eventCtx.startTimezone || ''),
      endDateTime: String(eventCtx.endDateTime || ''),
      organizerEmail: String(eventCtx.organizerEmail || ''),
      organizerName: String(eventCtx.organizerName || ''),
      internalAttendees: String(eventCtx.internalAttendees || ''),
      externalAttendeeEmails: String(eventCtx.externalAttendeeEmails || ''),
      currentAttendeeEmail: String(eventCtx.currentAttendeeEmail || ''),
      currentAttendeeName: String(eventCtx.currentAttendeeName || ''),
      calendlyParsed: eventCtx.calendlyParsed === true,
      sourceType: eventCtx.calendlyParsed ? 'Calendly body parser'
        : (eventCtx.organizerEmail && eventCtx.organizerEmail.toLowerCase() === extractedEmail)
          ? 'external organizer'
          : 'Outlook attendee'
    }});
  }
}

return results.length > 0 ? results : [{ json: {
  leadFound: false, leadId: null, leadEmail: '', currentAttendeeEmail: ''
}}];

// Runs once for ALL matched leads. Processes each one and outputs one item per lead.
const results = [];
for (const inputItem of $input.all()) {
  const d = inputItem.json;
  if (!d || !d.leadId || !d.outlookEventId) continue;

  const meetingKey = String(d.outlookEventId) + '_' + String(d.leadId);

  const tzMap = {
    'Pacific Standard Time': 'America/Los_Angeles',
    'Pacific Daylight Time': 'America/Los_Angeles',
    'Mountain Standard Time': 'America/Denver',
    'Mountain Daylight Time': 'America/Denver',
    'Central Standard Time': 'America/Chicago',
    'Central Daylight Time': 'America/Chicago',
    'Eastern Standard Time': 'America/New_York',
    'Eastern Daylight Time': 'America/New_York',
    'UTC': 'America/Los_Angeles'
  };
  const rawTz = String(d.startTimezone || '');
  const meetingTz = tzMap[rawTz] || (rawTz.startsWith('America/') ? rawTz : 'America/Los_Angeles');

  const meetingStart = new Date(d.startDateTime);
  const reminder24h = new Date(meetingStart.getTime() - 24 * 60 * 60 * 1000);
  const reminder1h  = new Date(meetingStart.getTime() -  1 * 60 * 60 * 1000);

  const meetingSource = d.calendlyParsed ? 'Calendly' : 'Outlook';
  const calendlyNote = d.calendlyParsed
    ? 'Calendly invitee email parsed from Outlook event body.'
    : '';

  results.push({ json: {
    meetingKey,
    meetingTz,
    meetingStartISO: meetingStart.toISOString(),
    reminder24hISO: reminder24h.toISOString(),
    reminder24hDate: reminder24h.toISOString().substring(0, 10),
    reminder1hISO: reminder1h.toISOString(),
    reminder1hDate: reminder1h.toISOString().substring(0, 10),
    meetingSource,
    calendlyNote,
    calendlyParsed: d.calendlyParsed === true,
    senderEmail: 'user@example.com',
    colleagueEmail: 'colleague@example.com',
    leadId: String(d.leadId || ''),
    leadName: String(d.leadName || ''),
    leadStatus: String(d.leadStatus || ''),
    leadEmail: String(d.leadEmail || ''),
    calendarSource: String(d.calendarSource || ''),
    outlookEventId: String(d.outlookEventId || ''),
    subject: String(d.subject || ''),
    endDateTime: String(d.endDateTime || ''),
    organizerEmail: String(d.organizerEmail || ''),
    organizerName: String(d.organizerName || ''),
    internalAttendees: String(d.internalAttendees || ''),
    externalAttendeeEmails: String(d.externalAttendeeEmails || '')
  }});
}
return results.length > 0 ? results : [{ json: { skip: true } }];

// Receives all items from Call W11 (one per lead that passed through).
// W11 runs once (for the first item's reminder date due to Execute Workflow limitations).
// We apply the same W11 result to all items, or fall back gracefully.
const calcItems = $('Calculate Meeting Key + Reminder Times').all();
const results = [];
let w11Result = null;
try {
  const w11Items = $input.all();
  if (w11Items && w11Items.length > 0) w11Result = w11Items[0].json;
} catch(e) {}

for (const calcItem of calcItems) {
  const calc = calcItem.json;
  if (calc.skip) continue;
  let reminder24hDate = String(calc.reminder24hDate || '');
  let holidayNote = '';
  try {
    if (w11Result && w11Result.isBusinessDay === false) {
      reminder24hDate = String(w11Result.previousBusinessDay || reminder24hDate);
      holidayNote = 'Original 24h reminder (' + calc.reminder24hDate + ') was ' + w11Result.reason + '. Moved to: ' + reminder24hDate;
    }
  } catch(e) {
    holidayNote = 'W11 check skipped';
  }
  results.push({ json: { ...calc, reminder24hDate, holidayNote } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

const results = [];
for (const item of $('Resolve Meeting Number').all()) {
  if (item.json.skip) continue;
  results.push({ json: { ...item.json } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

