// Guaranteed path: always receives input from Normalize Pre-Check.
// Reads Pre-Count output via node reference to get counts per Lead.
const preCheckItems = $('Normalize Pre-Check').all();

// Build count lookup: leadId -> count of OTHER non-cancelled meetings
const countByLead = {};
try {
  for (const c of $('Pre-Count Tracker Records').all()) {
    if (c.json && c.json.Related_Lead__c) {
      countByLead[String(c.json.Related_Lead__c)] = Number(c.json.total || c.json.expr0 || 0);
    }
  }
} catch(e) {}

const results = [];
for (const preCheck of preCheckItems) {
  const calc = preCheck.json;
  if (calc.skip) continue;
  const otherCount = countByLead[calc.leadId] || 0;
  const trueCount = otherCount + 1;
  results.push({ json: { ...calc, trueCount, meetingNumberResolved: trueCount } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

// Receives Apply W11 output (all items) and Pre-Check tracker results.
// Matches each item to its tracker by meetingKey.
const w11Items = $('Apply W11 \u2014 Update 24h Date If Needed').all();

// Build tracker lookup: meetingKey -> tracker record
const trackerByKey = {};
try {
  for (const t of $('Pre-Check Tracker Exists').all()) {
    if (t.json && t.json.Meeting_Key__c) {
      trackerByKey[String(t.json.Meeting_Key__c)] = t.json;
    }
  }
} catch(e) {}

const results = [];
for (const w11Item of w11Items) {
  const calc = w11Item.json;
  if (calc.skip) continue;

  let isNewRecord = true;
  let needs24hTask = true;
  let needs1hTask = true;

  const rec = trackerByKey[calc.meetingKey];
  if (rec && rec.Id) {
    isNewRecord = false;
    needs24hTask = rec.X24_Hour_Reminder_Task_Created__c !== true;
    needs1hTask  = rec.X1_Hour_Reminder_Task_Created__c  !== true;
  }

  results.push({ json: { isNewRecord, needs24hTask, needs1hTask, ...calc } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

