// Receives all items from Resolve True Meeting Count.
// Reads Check SF Event Exists Raw results and matches by WhoId+StartDateTime.
const ctxItems = $('Resolve True Meeting Count').all();

// Build event lookup: leadId+'|'+startISO -> eventId
const eventByKey = {};
try {
  for (const ev of $('Check SF Event Exists Raw').all()) {
    if (ev.json && ev.json.Id && ev.json.WhoId) {
      // StartDateTime from SF comes back as ISO, normalize
      const start = String(ev.json.StartDateTime || '').replace(/\.000\+0000$/, 'Z');
      const key = String(ev.json.WhoId) + '|' + start;
      eventByKey[key] = String(ev.json.Id);
    }
  }
} catch(e) {}

const results = [];
for (const ctxItem of ctxItems) {
  const ctx = ctxItem.json;
  if (ctx.skip) continue;
  // Try to match: normalize meetingStartISO
  const normStart = String(ctx.meetingStartISO || '').replace(/\.000Z$/, 'Z');
  const lookupKey = String(ctx.leadId) + '|' + normStart;
  const eventId = eventByKey[lookupKey] || null;
  const eventExists = !!eventId;
  results.push({ json: { ...ctx, eventExists, eventId } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

