={{ (function() {
  const items = $('Resolve True Meeting Count').all().filter(i => !i.json.skip);
  if (!items.length) return "SELECT Id, WhoId, StartDateTime FROM Event WHERE Id = null LIMIT 1";
  const conditions = items.map(i => 
    "(WhoId = '" + i.json.leadId + "' AND StartDateTime = " + i.json.meetingStartISO + ")"
  ).join(' OR ');
  return "SELECT Id, WhoId, StartDateTime FROM Event WHERE " + conditions + " LIMIT " + (items.length + 5);
})() }}

