// After event creation/skip, recover full context from Check + Route SF Event.
// The event create node only returns {id, success, errors} — we need the full Lead context.
// Check + Route SF Event has the full batch; match by position.
const ctxItems = $('Check + Route SF Event').all();
const results = [];
for (const ctx of ctxItems) {
  if (ctx.json.skip) continue;
  results.push({ json: { ...ctx.json } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

// Sequential: receives input from Recover Context After 1h Task.
// At this point, both 24h AND 1h task branches have fully completed.
// Read task flags from both Recover Context nodes keyed by meetingKey.
const items24h = $('Recover Context After 24h Check').all();
const items1h  = $('Recover Context After 1h Task').all();

// Build lookup: meetingKey -> flags
const flagBy24h = {};
for (const item of items24h) {
  if (item.json && item.json.meetingKey) {
    flagBy24h[item.json.meetingKey] = item.json;
  }
}
const flagBy1h = {};
for (const item of items1h) {
  if (item.json && item.json.meetingKey) {
    flagBy1h[item.json.meetingKey] = item.json;
  }
}

const results = [];
for (const item of $input.all()) {
  const ctx = item.json;
  if (!ctx || ctx.skip) continue;
  const mk = ctx.meetingKey;
  const f24 = flagBy24h[mk] || {};
  const f1h = flagBy1h[mk]  || {};
  // task24hExistsOrCreated: soqlExists OR (needs24hTask was true = Create branch ran)
  const task24hExistsOrCreated = f24.soql24hExists === true || f24.needs24hTask === true;
  // task1hExistsOrCreated: from Recover Context After 1h Task which computed it
  const task1hExistsOrCreated  = f1h.task1hExistsOrCreated === true;
  results.push({ json: {
    ...ctx,
    soql24hExists: f24.soql24hExists || false,
    soql1hExists:  f1h.soql1hExists  || false,
    task24hExistsOrCreated,
    task1hExistsOrCreated
  }});
}
return results.length > 0 ? results : [{ json: { skip: true } }];

// After Lead update nodes (which return success/error), recover full Lead context.
// Read from Merge Event Result which has the full context for all leads.
const ctxItems = $('Merge Event Result').all();
const results = [];
for (const ctx of ctxItems) {
  if (ctx.json.skip) continue;
  results.push({ json: { ...ctx.json } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

// Batch-safe: process ALL items from Recover Context After Lead Update.
// Reads Check Review Task Exists SOQL results and matches by meetingKey in Description.
// No Description LIKE in SOQL — we filter in code instead.
//
// GUARD 1: If the Lead already has >= 1 Meeting Reminder Tracker record
// (i.e. this is NOT their first meeting), skip the review task entirely.
//
// GUARD 2: If the Lead status is already in a booked/completed/follow-up state,
// skip the review task regardless of tracker count.
const ctxItems = $('Recover Context After Lead Update').all();
const soqlItems = $('Check Review Task Exists').all();

// Statuses that indicate the Lead is already past the point where the review task is useful.
// Case-insensitive match applied below.
const SKIP_STATUSES = [
  'appointment booked',
  'app booked',
  'discovery completed',
  'follow-up meeting',
  'follow up meeting'
];

// Build count lookup: leadId -> count of OTHER non-cancelled tracker records
const trackerCountByLead = {};
try {
  for (const c of $('Pre-Count Tracker Records').all()) {
    if (c.json && c.json.Related_Lead__c) {
      trackerCountByLead[String(c.json.Related_Lead__c)] = Number(c.json.total || c.json.expr0 || 0);
    }
  }
} catch(e) {}

// Build set of task descriptions returned for this lead
const taskDescriptions = soqlItems
  .map(si => String(si.json && si.json.Description ? si.json.Description : ''))
  .filter(d => d.length > 0);

const results = [];
for (const ctxItem of ctxItems) {
  const ctx = ctxItem.json;
  if (!ctx || ctx.skip) continue;

  // GUARD 1: tracker count >= 1 → skip
  const otherTrackerCount = trackerCountByLead[ctx.leadId] || 0;
  if (otherTrackerCount >= 1) {
    results.push({ json: { ...ctx, reviewTaskExists: true, reviewTaskSkipReason: 'tracker_count_' + otherTrackerCount } });
    continue;
  }

  // GUARD 2: Lead status already booked/completed/follow-up → skip
  const statusNorm = String(ctx.leadStatus || '').toLowerCase().trim();
  if (SKIP_STATUSES.includes(statusNorm)) {
    results.push({ json: { ...ctx, reviewTaskExists: true, reviewTaskSkipReason: 'lead_status_' + statusNorm } });
    continue;
  }

